create table public.api_keys(id uuid primary key,seller_account_id uuid not null references public.seller_accounts(id) on delete cascade,name text not null,key_prefix text not null,key_hash text not null unique,scopes text[] not null default '{}',last_used_at timestamptz,expires_at timestamptz,revoked_at timestamptz,created_at timestamptz not null default now());
create table public.api_request_logs(id uuid primary key default gen_random_uuid(),api_key_id uuid not null references public.api_keys(id) on delete cascade,seller_account_id uuid not null references public.seller_accounts(id),method text not null,path text not null,status integer,request_id text not null,created_at timestamptz not null default now());
create table public.outbound_webhooks(id uuid primary key default gen_random_uuid(),seller_account_id uuid not null references public.seller_accounts(id) on delete cascade,url text not null,secret_encrypted text not null,event_types text[] not null,active boolean not null default true,created_at timestamptz not null default now());
create table public.webhook_deliveries(id uuid primary key default gen_random_uuid(),webhook_id uuid not null references public.outbound_webhooks(id) on delete cascade,seller_account_id uuid not null references public.seller_accounts(id),event_id text not null,payload jsonb not null,state text not null default 'queued' check(state in ('queued','delivering','delivered','retry','dead_letter')),attempt_count integer not null default 0,next_attempt_at timestamptz not null default now(),last_error text,delivered_at timestamptz,unique(webhook_id,event_id));
create table public.automation_rules(id uuid primary key default gen_random_uuid(),seller_account_id uuid not null references public.seller_accounts(id) on delete cascade,name text not null,event_type text not null,conditions jsonb not null default '{}',action jsonb not null,active boolean not null default true,created_at timestamptz not null default now());
create table public.automation_runs(id uuid primary key default gen_random_uuid(),rule_id uuid not null references public.automation_rules(id) on delete cascade,seller_account_id uuid not null references public.seller_accounts(id),event_id text not null,depth integer not null default 0,state text not null default 'pending' check(state in ('pending','completed','skipped','failed')),result jsonb,created_at timestamptz not null default now(),unique(rule_id,event_id),check(depth between 0 and 4));
do $$declare t text;begin foreach t in array array['api_keys','api_request_logs','outbound_webhooks','webhook_deliveries','automation_rules','automation_runs'] loop execute format('alter table public.%I enable row level security',t);execute format('alter table public.%I force row level security',t);end loop;end$$;
create policy api_keys_owner_all on public.api_keys for all to authenticated using(seller_account_id=(select public.current_seller_account_id())) with check(seller_account_id=(select public.current_seller_account_id()));
create policy api_logs_owner_read on public.api_request_logs for select to authenticated using(seller_account_id=(select public.current_seller_account_id()));
create policy outbound_webhooks_owner_all on public.outbound_webhooks for all to authenticated using(seller_account_id=(select public.current_seller_account_id())) with check(seller_account_id=(select public.current_seller_account_id()));
create policy webhook_deliveries_owner_read on public.webhook_deliveries for select to authenticated using(seller_account_id=(select public.current_seller_account_id()));
create policy automation_rules_owner_all on public.automation_rules for all to authenticated using(seller_account_id=(select public.current_seller_account_id())) with check(seller_account_id=(select public.current_seller_account_id()));
create policy automation_runs_owner_read on public.automation_runs for select to authenticated using(seller_account_id=(select public.current_seller_account_id()));
grant select,insert,update,delete on public.api_keys,public.outbound_webhooks,public.automation_rules to authenticated;grant select on public.api_request_logs,public.webhook_deliveries,public.automation_runs to authenticated;grant all on public.api_keys,public.api_request_logs,public.outbound_webhooks,public.webhook_deliveries,public.automation_rules,public.automation_runs to service_role;
